import copy


def discount(code):
    return {
        '5% off': lambda price: round((10/100)*price, 2),
        'free shipping': lambda price: 0
    }[code]
    
def apply_discount(cart):
    for item in cart['items']:
        item['price'] = discount(item.get('discount'))
    return cart


def add_taxes(cart):
    taxes = {
        123456789: .08,
        345345345: .07,
        232323232: .09
    }[cart['customer']['id']]
    
    for item in cart['items']:
        item['price'] = round(item['price'] * (1 + taxes), 2)
        
    return cart